/* End of Number of days medications prescribed */
/* @dataElement: HIV.D.DE466 - Type of treatment-limiting toxicity @activity: HIV.D21 Determine regimen and treatment options @description: Type of treatment-limiting toxicity experienced by client. Treatment-limiting toxicity is defined as a serious adverse drug reaction that results in drug discontinuation or substitution. In addition, any reaction that leads to treatment interruption or requires changing the drug or regimen because of an adverse drug reaction is also considered a serious adverse drug reaction. */
define "Type of treatment-limiting toxicity": case when "Gastrointestinal" then Concepts."Gastrointestinal" when "Skin issues" then Concepts."Skin issues" when "Peripheral neuropathy" then Concepts."Peripheral neuropathy" when "Central nervous system symptoms" then Concepts."Central nervous system symptoms" when "Weight gain" then Concepts."Weight gain" when "Hepatic dysfunction" then Concepts."Hepatic dysfunction" when "Haematological disorders" then Concepts."Haematological disorders" when "Fatigue" then Concepts."Fatigue" when "Headache D.DE475" then Concepts."Headache - HIV.D.DE475" when "Bone dysfunction" then Concepts."Bone dysfunction" when "Metabolic symptoms" then Concepts."Metabolic symptoms" when "Kidney dysfunction" then Concepts."Kidney dysfunction" when "Unexpected adverse drug reaction" then Concepts."Unexpected adverse drug reaction" else null end

/* End of Facility-level testing */

/*
@dataElement: HIV.B.DE29 - Currently pregnant
@activity: HIV.B6 Capture or update client history
@description: Client is currently pregnant
*/

define "Currently pregnant B.DE29":
  [Condition: Concepts."Currently pregnant - HIV.B.DE29"] C
  sort by start of prevalenceInterval()

/* End of Facility-level testing */

/*
@dataElement: HIV.B.DE29 - Currently pregnant
@activity: HIV.B6 Capture or update client history
@description: Client is currently pregnant
*/

define "Currently pregnant B.DE29":
